var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"어이, 여기 이 잔해들 좀 봐.","JPN":"おい、すごい量の瓦礫だぞ。","ENG":"Hey, look at all this debris.","TWN":"喂，看看這裡的殘骸。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"여기서 폭발이 있었던 것 같은데?","JPN":"ここで爆発があったみたいだな。","ENG":"Looks like there was an explosion here.","TWN":"這裡好像發生過爆炸？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"흔적을 봐선 바깥이 아니라 시설 내부에서 폭발물을 쓴 모양이야.","JPN":"形跡から推測するに、外からではなく、施設内部で爆発物が使われたみたいだ。","ENG":"The traces show that the explosives were used from inside the facility, not outside.","TWN":"從痕跡來看，爆炸似乎發生在設施內。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"왜 이런 걸 여기서 터트린 걸까요? 여긴 비싼 전자장비도 많아 보이는데.","JPN":"どうしてそんなものを高そうな電子装備がたくさんあるところで使ったんでしょうか？","ENG":"Why would they blow it up from here? There seems to be a lot of expensive equipment here too.","TWN":"為什麼會發生這種事情？這裡面似乎有很多昂貴的電子裝備啊？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"만일을 대비해 시설을 폭파하려던 거겠지. 기술유출은 중대 사안이니까.","JPN":"もしもの事態に備えて施設を爆破しようとしてたんだろうな。技術流出は重大な問題だから。","ENG":"They were probably planning on blowing up the whole facility as a precaution. Tech leaks are a serious matter.","TWN":"可能是為了以防萬一才炸毀設施，為了阻止技術洩露。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"하지만 터미널이 멀쩡히 작동한다는 건, 화력이 부족했던 건가?","JPN":"しかしまだターミナルは作動いている。つまり火力が足りなかったってことなのか？","ENG":"But if the terminal's fine, doesn't that mean there wasn't enough firepower?","TWN":"但終端還能正常工作，是因為火力不夠嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"둘 중 하나야.","JPN":"どちらかだろう。","ENG":"There are two possibilities.","TWN":"有兩種情況。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"기록말소에 실패했거나, 아니면 시설이 아닌 다른 무언가를 제거하려고 했거나.","JPN":"記録の抹消に失敗したか、施設じゃない何かを消そうとしたか。","ENG":"Either they failed to erase the records, or they were trying to eliminate something else besides the facility.","TWN":"他們要麼是未能刪除記錄，要麼想要刪除的是其他東西。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그리고 이 바닥에 널려 있는 가루는 탄화 이터니움의 흔적이야.","JPN":"それに、床に散らばっている粉末。炭化エタニウムを使った痕跡だ。","ENG":"And the dust scattered here are traces of carbonized Eternium.","TWN":"並且地板上散落的粉末，是永恆之金碳化的痕跡。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"통상적으로, 폭발물에 값비싼 이터니움을 쓰는 경우는 하나뿐이지.","JPN":"通常、爆発物に高価なエタニウムを使用する理由は一つしかない。","ENG":"Typically, there's only one reason why you would use such expensive material in an explosive.","TWN":"通常，只有一種情況會使用昂貴的永恆之金作為炸藥。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"침식체를 제거하려고 했군.","JPN":"侵食体を吹き飛ばすためか。","ENG":"To take down C.O.s.","TWN":"為了消滅侵蝕體。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"하긴… 이 정도 심도에선 언제 어디서 고위 침식체가 튀어나와도 이상하지 않으니까.","JPN":"なるほど……ここまでの深度となれば、いつどこから高レベルの侵食体が飛び出してきても不思議ではないからな。","ENG":"Well... it wouldn't be surprising for a high-tier C.O. to just pop out at this depth.","TWN":"好吧……在這個深度，隨時隨地冒出高級侵蝕體也不足為奇了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"조심해야겠네요. 그 고위 침식체가 아직 이 시설에 남아있을 수도 있으니까요.","JPN":"でしたら気をつけた方がよさそうですね。その高レベルの侵食体がまだ残っているかもしれませんから。","ENG":"We should take care. That high-tier C.O. might still be around.","TWN":"噢噢！大家小心！這麼說這個高階侵蝕體可能仍然留在這個設施裡。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"더 조심하고 말고 할 것도 없어. 이미 여긴 동면에서 깨어난 침식체투성인데 뭐.","JPN":"今更気をつけるもなにもないさ。もうここは冬眠から目覚めた侵食体だらけだからな。","ENG":"More care ain't gonna help us. This place is already crawling with C.O.s waking up from their hibernation.","TWN":"就算再怎麼小心也沒有用吧？這裡早就爬滿了從冬眠中甦醒的侵蝕體……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_SURPRISE"},"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"방금 그건 뭐였지? 지진인가?","JPN":"今のはなんだ？　地震？","ENG":"What was that? An earthquake?","TWN":"剛才那是什麼？是地震嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"여기 오래 있는 건 좋지 않아. 서둘러 움직이자.","JPN":"ここに長居するのはよくなさそうだ。急いで離れよう。","ENG":"It's not good to stay here for long. Let's move.","TWN":"看來這裡也待不長了。我們快點行動吧。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};